def convert_jsonl(input_file, output_file):
    with open(input_file, "r", encoding="utf-8") as f_in, open(output_file, "w", encoding="utf-8") as f_out:
        for line in f_in:
            data = json.loads(line.strip())

            # 提取 video_url（假设在 user 的 content 里）
            video_url_info = None
            for msg in data.get("messages", []):
                if msg.get("role") == "user":
                    for c in msg.get("content", []):
                        if c.get("type") == "video_url":
                            video_url_info = c.get("video_url")

            # 提取 assistant 的回答作为 ground_truth
            ground_truth_text = None
            for msg in data.get("messages", []):
                if msg.get("role") == "assistant":
                    ground_truth_text = msg.get("content")

            # 构造目标格式
            converted = {
                "data_source": "data_source",
                "prompt": [
                    {
                        "role": "user",
                        "content": [
                            {
                                "type": "video_url",
                                "video_url": video_url_info  # 保留原始 video_url
                            },
                            {
                                "type": "text",
                                "text": "<VIDEO_CONTEXT>\nDescribe the video in detail."
                            }
                        ]
                    }
                ],
                "ability": "test",
                "reward_model": {
                    "style": "general",
                    "ground_truth": "A"  # 使用 assistant 的回答
                },
                "extra_info": {}
            }

            f_out.write(json.dumps(converted, ensure_ascii=False) + "\n")


